#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <cuda.h>
#include <cuda_runtime.h>

#include "main.h"
#include "device.h"
#include "util/timer/timer.h"

__global__ void kernel_gpu_cuda(par_str par,
                                dim_str dim,
                                const box_str* box,
                                const FOUR_VECTOR* rv,
                                const fp* qv,
                                FOUR_VECTOR* fv,
                                fp a2) {
    int l = blockIdx.x;
    int i = threadIdx.x;

    if (l < dim.number_boxes && i < NUMBER_PAR_PER_BOX) {
        long first_i = box[l].offset;

        FOUR_VECTOR rA_i = rv[first_i + i];
        FOUR_VECTOR fA_i = fv[first_i + i];

        for (int k = 0; k < (1 + box[l].nn); k++) {
            int pointer;
            if (k == 0) {
                pointer = l;
            } else {
                pointer = box[l].nei[k - 1].number;
            }

            long first_j = box[pointer].offset;

            for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
                FOUR_VECTOR rB_j = rv[first_j + j];
                fp qB_j = qv[first_j + j];

                fp r2 = rA_i.v + rB_j.v - (rA_i.x * rB_j.x + rA_i.y * rB_j.y + rA_i.z * rB_j.z);
                fp u2 = a2 * r2;
                fp vij = exp(-u2);
                fp fs = 2.0 * vij;

                fp dx = rA_i.x - rB_j.x;
                fp dy = rA_i.y - rB_j.y;
                fp dz = rA_i.z - rB_j.z;

                fp fxij = fs * dx;
                fp fyij = fs * dy;
                fp fzij = fs * dz;

                fA_i.v += qB_j * vij;
                fA_i.x += qB_j * fxij;
                fA_i.y += qB_j * fyij;
                fA_i.z += qB_j * fzij;
            }
        }

        fv[first_i + i] = fA_i;
    }
}

void kernel_cpu(par_str par,
                dim_str dim,
                box_str* box,
                FOUR_VECTOR* rv,
                fp* qv,
                FOUR_VECTOR* fv) {
    long long time0;
    time0 = get_time();

    long long time1;
    long long time2;
    long long time3;
    long long time4;

    fp alpha;
    fp a2;

    time1 = get_time();

    setdevice();

    time2 = get_time();

    alpha = par.alpha;
    a2 = 2.0 * alpha * alpha;

    box_str* d_box = NULL;
    FOUR_VECTOR* d_rv = NULL;
    fp* d_qv = NULL;
    FOUR_VECTOR* d_fv = NULL;

    cudaMalloc((void**)&d_box, dim.box_mem);
    cudaMalloc((void**)&d_rv, dim.space_mem);
    cudaMalloc((void**)&d_qv, dim.space_mem2);
    cudaMalloc((void**)&d_fv, dim.space_mem);
    checkCUDAError("cudaMalloc");

    cudaMemcpy(d_box, box, dim.box_mem, cudaMemcpyHostToDevice);
    cudaMemcpy(d_rv, rv, dim.space_mem, cudaMemcpyHostToDevice);
    cudaMemcpy(d_qv, qv, dim.space_mem2, cudaMemcpyHostToDevice);
    cudaMemcpy(d_fv, fv, dim.space_mem, cudaMemcpyHostToDevice);
    checkCUDAError("cudaMemcpy H2D");

    time3 = get_time();

    dim3 threads(NUMBER_PAR_PER_BOX, 1, 1);
    dim3 blocks((unsigned int)dim.number_boxes, 1, 1);

    kernel_gpu_cuda<<<blocks, threads>>>(par, dim, d_box, d_rv, d_qv, d_fv, a2);
    cudaDeviceSynchronize();
    checkCUDAError("kernel_gpu_cuda");

    cudaMemcpy(fv, d_fv, dim.space_mem, cudaMemcpyDeviceToHost);
    checkCUDAError("cudaMemcpy D2H");

    cudaFree(d_box);
    cudaFree(d_rv);
    cudaFree(d_qv);
    cudaFree(d_fv);

    time4 = get_time();

    printf("Time spent in different stages of CPU/MCPU KERNEL:\n");

    printf("%15.12f s, %15.12f % : CPU/MCPU: VARIABLES\n", (float)(time1 - time0) / 1000000, (float)(time1 - time0) / (float)(time4 - time0) * 100);
    printf("%15.12f s, %15.12f % : MCPU: SET DEVICE\n", (float)(time2 - time1) / 1000000, (float)(time2 - time1) / (float)(time4 - time0) * 100);
    printf("%15.12f s, %15.12f % : CPU/MCPU: INPUTS\n", (float)(time3 - time2) / 1000000, (float)(time3 - time2) / (float)(time4 - time0) * 100);
    printf("%15.12f s, %15.12f % : CPU/MCPU: KERNEL\n", (float)(time4 - time3) / 1000000, (float)(time4 - time3) / (float)(time4 - time0) * 100);

    printf("Total time:\n");
    printf("%.12f s\n", (float)(time4 - time0) / 1000000);
}

#ifdef __cplusplus
}
#endif

