#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#include <string.h>
#include <time.h>

#include "util/timer/timer.h"
#include "util/num/num.h"
#include "main.h"

#ifdef __cplusplus
extern "C" {
#endif
void kernel_cpu(par_str par,
                dim_str dim,
                box_str* box,
                FOUR_VECTOR* rv,
                fp* qv,
                FOUR_VECTOR* fv);
#ifdef __cplusplus
}
#endif

int main(int argc, char *argv[]) {
    long long time0;
    time0 = get_time();

    long long time1;
    long long time2;
    long long time3;
    long long time4;
    long long time5;
    long long time6;
    long long time7;

    int i, j, k, l, m, n;

    par_str par_cpu;
    dim_str dim_cpu;
    box_str* box_cpu;
    FOUR_VECTOR* rv_cpu;
    fp* qv_cpu;
    FOUR_VECTOR* fv_cpu;
    int nh;

    time1 = get_time();

    dim_cpu.cores_arg = 1;
    dim_cpu.boxes1d_arg = 1;

    for (dim_cpu.cur_arg = 1; dim_cpu.cur_arg < argc; dim_cpu.cur_arg++) {
        if (strcmp(argv[dim_cpu.cur_arg], "-cores") == 0) {
            if (argc >= dim_cpu.cur_arg + 1) {
                if (isInteger(argv[dim_cpu.cur_arg + 1]) == 1) {
                    dim_cpu.cores_arg = atoi(argv[dim_cpu.cur_arg + 1]);
                    if (dim_cpu.cores_arg < 0) {
                        printf("ERROR: Wrong value to -cores parameter, cannot be <=0\n");
                        return 0;
                    }
                    dim_cpu.cur_arg = dim_cpu.cur_arg + 1;
                } else {
                    printf("ERROR: Value to -cores parameter in not a number\n");
                    return 0;
                }
            } else {
                printf("ERROR: Missing value to -cores parameter\n");
                return 0;
            }
        } else if (strcmp(argv[dim_cpu.cur_arg], "-boxes1d") == 0) {
            if (argc >= dim_cpu.cur_arg + 1) {
                if (isInteger(argv[dim_cpu.cur_arg + 1]) == 1) {
                    dim_cpu.boxes1d_arg = atoi(argv[dim_cpu.cur_arg + 1]);
                    if (dim_cpu.boxes1d_arg < 0) {
                        printf("ERROR: Wrong value to -boxes1d parameter, cannot be <=0\n");
                        return 0;
                    }
                    dim_cpu.cur_arg = dim_cpu.cur_arg + 1;
                } else {
                    printf("ERROR: Value to -boxes1d parameter in not a number\n");
                    return 0;
                }
            } else {
                printf("ERROR: Missing value to -boxes1d parameter\n");
                return 0;
            }
        } else {
            printf("ERROR: Unknown parameter\n");
            return 0;
        }
    }

    printf("Configuration used: cores = %d, boxes1d = %d\n", dim_cpu.cores_arg, dim_cpu.boxes1d_arg);

    time2 = get_time();

    par_cpu.alpha = 0.5;

    time3 = get_time();

    dim_cpu.number_boxes = dim_cpu.boxes1d_arg * dim_cpu.boxes1d_arg * dim_cpu.boxes1d_arg;

    dim_cpu.space_elem = dim_cpu.number_boxes * NUMBER_PAR_PER_BOX;
    dim_cpu.space_mem = dim_cpu.space_elem * sizeof(FOUR_VECTOR);
    dim_cpu.space_mem2 = dim_cpu.space_elem * sizeof(fp);

    dim_cpu.box_mem = dim_cpu.number_boxes * sizeof(box_str);

    time4 = get_time();

    box_cpu = (box_str*)malloc(dim_cpu.box_mem);

    nh = 0;

    for (i = 0; i < dim_cpu.boxes1d_arg; i++) {
        for (j = 0; j < dim_cpu.boxes1d_arg; j++) {
            for (k = 0; k < dim_cpu.boxes1d_arg; k++) {
                box_cpu[nh].x = k;
                box_cpu[nh].y = j;
                box_cpu[nh].z = i;
                box_cpu[nh].number = nh;
                box_cpu[nh].offset = nh * NUMBER_PAR_PER_BOX;

                box_cpu[nh].nn = 0;

                for (l = -1; l < 2; l++) {
                    for (m = -1; m < 2; m++) {
                        for (n = -1; n < 2; n++) {
                            if ((((i + l) >= 0 && (j + m) >= 0 && (k + n) >= 0) == true &&
                                 ((i + l) < dim_cpu.boxes1d_arg && (j + m) < dim_cpu.boxes1d_arg && (k + n) < dim_cpu.boxes1d_arg) == true) &&
                                (l == 0 && m == 0 && n == 0) == false) {
                                box_cpu[nh].nei[box_cpu[nh].nn].x = (k + n);
                                box_cpu[nh].nei[box_cpu[nh].nn].y = (j + m);
                                box_cpu[nh].nei[box_cpu[nh].nn].z = (i + l);
                                box_cpu[nh].nei[box_cpu[nh].nn].number =
                                    (box_cpu[nh].nei[box_cpu[nh].nn].z * dim_cpu.boxes1d_arg * dim_cpu.boxes1d_arg) +
                                    (box_cpu[nh].nei[box_cpu[nh].nn].y * dim_cpu.boxes1d_arg) +
                                    box_cpu[nh].nei[box_cpu[nh].nn].x;
                                box_cpu[nh].nei[box_cpu[nh].nn].offset = box_cpu[nh].nei[box_cpu[nh].nn].number * NUMBER_PAR_PER_BOX;

                                box_cpu[nh].nn = box_cpu[nh].nn + 1;
                            }
                        }
                    }
                }

                nh = nh + 1;
            }
        }
    }

    srand(time(NULL));

    rv_cpu = (FOUR_VECTOR*)malloc(dim_cpu.space_mem);
    for (i = 0; i < dim_cpu.space_elem; i = i + 1) {
        rv_cpu[i].v = (rand() % 10 + 1) / 10.0;
        rv_cpu[i].x = (rand() % 10 + 1) / 10.0;
        rv_cpu[i].y = (rand() % 10 + 1) / 10.0;
        rv_cpu[i].z = (rand() % 10 + 1) / 10.0;
    }

    qv_cpu = (fp*)malloc(dim_cpu.space_mem2);
    for (i = 0; i < dim_cpu.space_elem; i = i + 1) {
        qv_cpu[i] = (rand() % 10 + 1) / 10.0;
    }

    fv_cpu = (FOUR_VECTOR*)malloc(dim_cpu.space_mem);
    for (i = 0; i < dim_cpu.space_elem; i = i + 1) {
        fv_cpu[i].v = 0;
        fv_cpu[i].x = 0;
        fv_cpu[i].y = 0;
        fv_cpu[i].z = 0;
    }

    time5 = get_time();

    kernel_cpu(par_cpu,
               dim_cpu,
               box_cpu,
               rv_cpu,
               qv_cpu,
               fv_cpu);

    time6 = get_time();

#ifdef OUTPUT
    FILE *fptr;
    fptr = fopen("result.txt", "w");
    for (i = 0; i < dim_cpu.space_elem; i = i + 1) {
        fprintf(fptr, "%f, %f, %f, %f\n", fv_cpu[i].v, fv_cpu[i].x, fv_cpu[i].y, fv_cpu[i].z);
    }
    fclose(fptr);
#endif

    free(rv_cpu);
    free(qv_cpu);
    free(fv_cpu);
    free(box_cpu);

    time7 = get_time();

    return 0.0;
}
